-- Create flakiness history table CREATE TABLE IF NOT EXISTS test_flakiness_history ( id SERIAL PRIMARY KEY, test_signature TEXT NOT NULL, test_name TEXT NOT NULL, test_file TEXT NOT NULL, flakiness_score DECIMAL(5,2) NOT NULL, total_runs INTEGER NOT NULL, flaky_runs INTEGER NOT NULL, calculated_at TIMESTAMPTZ DEFAULT NOW(), date_range_start TIMESTAMPTZ NOT NULL, date_range_end TIMESTAMPTZ NOT NULL );
-- Index for lookups CREATE INDEX IF NOT EXISTS idx_flakiness_signature ON test_flakiness_history(test_signature);
CREATE INDEX IF NOT EXISTS idx_flakiness_calculated_at ON test_flakiness_history(calculated_at);
